'use client';

import './globals.css';
import { AuthProvider } from '@/context/AuthContext';
import { GeistSans } from 'geist/font/sans';
import NotificationBell from '@/components/NotificationBell';
import { useRouter } from 'next/navigation';
import { useAuth } from '@/context/AuthContext';

export default function RootLayout({ children }) {
  const router = useRouter();
  const { user } = useAuth();

  const handleLogout = async () => {
    const { error } = await supabase.auth.signOut();
    if (!error) router.push('/auth');
  };

  return (
    <html lang="en" className={GeistSans.className}>
      <body className="bg-gray-100 text-black">
        <AuthProvider>
          {/* Navigation Bar */}
          <nav className="bg-white shadow p-4 flex justify-between items-center">
            <div className="text-xl font-bold text-purple-600">Creative Justice</div>

            {user && (
              <div className="flex items-center gap-4">
                <button onClick={() => router.push('/feed')} className="hover:underline">
                  Home
                </button>
                <button onClick={() => router.push('/my_network')} className="hover:underline">
                  My Network
                </button>
                <button onClick={() => router.push('/profile')} className="hover:underline">
                  Profile
                </button>
                <NotificationBell />
                <button onClick={handleLogout} className="text-red-500 hover:underline">
                  Log Out
                </button>
              </div>
            )}
          </nav>

          {/* Main Page Content */}
          <main className="p-6 max-w-7xl mx-auto">{children}</main>
        </AuthProvider>
      </body>
    </html>
  );
}
